render.css:
.network-container { width: 100%; height: 140px; position: relative; }
.node { fill: var(--ct-bg-deep); stroke: var(--ct-text-strong); stroke-width: 1.5; }
.edge { fill: none; stroke: var(--ct-surface-3); stroke-width: 1; }
.packet { fill: var(--ct-text-strong); filter: drop-shadow(0 0 2px var(--ct-text-strong)); }
